installer-gui-script.script:
function installationCheck() {
    // Check if running on macOS 13 (Ventura) or later
    if (system.compareVersions(system.version.ProductVersion, '13.0') < 0) {
        my.result.title = 'Unsupported macOS Version';
        my.result.message = 'RPC Cluster Worker requires macOS 13 (Ventura) or later.';
        my.result.type = 'Fatal';
        return false;
    }
    return true;
}
